import{_ as e,c as t,o as r,a as o}from"./app.a0551527.js";const m=JSON.parse('{"title":"获取用户选中","description":"","frontmatter":{},"headers":[{"level":2,"title":"robot.js","slug":"robot-js","link":"#robot-js","children":[]},{"level":2,"title":"@nut-tree/nut-js","slug":"nut-tree-nut-js","link":"#nut-tree-nut-js","children":[]}],"relativePath":"3.框架/5.electron/获取用户选中.md","lastUpdated":1678874994000}'),a={name:"3.框架/5.electron/获取用户选中.md"},n=o('<h1 id="获取用户选中" tabindex="-1">获取用户选中 <a class="header-anchor" href="#获取用户选中" aria-hidden="true">#</a></h1><blockquote><p><a href="https://www.cnblogs.com/muwoo/p/14971743.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/muwoo/p/14971743.html</a></p></blockquote><p>百度翻译的桌面端软件可以做到滑译，即鼠标选中内容就在下方进行翻译，生成翻译框很好搞，electron支持窗口定位，但是怎么监听鼠标选中内容和获取内容呢，electron没有这种功能</p><p>最终发现用一个hack方法来实现这一功能：</p><ol><li>监听用户按下鼠标、松开鼠标事件</li><li>调用系统命令，复制选中内部到剪贴版，electron可以获取剪贴板</li><li>调用系统命令保存前，先保存用户之前的粘贴内容，最后需要恢复一下，从而达到用户无感知的效果</li></ol><p>综上，我们需要能监听系统鼠标事件、能调用系统复制功能的npm包，最好是多平台支持（windows、mac、linux）</p><h2 id="robot-js" tabindex="-1">robot.js <a class="header-anchor" href="#robot-js" aria-hidden="true">#</a></h2><p>已长时间不再维护</p><h2 id="nut-tree-nut-js" tabindex="-1">@nut-tree/nut-js <a class="header-anchor" href="#nut-tree-nut-js" aria-hidden="true">#</a></h2><p>有待尝试</p>',10),s=[n];function l(c,i,_,d,h,p){return r(),t("div",null,s)}const b=e(a,[["render",l]]);export{m as __pageData,b as default};
